"""
mkt-christ | zechariah | ch1–7
run: python3 scripts/zc-christ-zechariah-1-7.py
"""

import json, pathlib

ROOT = pathlib.Path(__file__).resolve().parent.parent

def load_comm(layer, book):
    p = ROOT / 'data' / 'commentary' / layer / f'{book}.json'
    return json.loads(p.read_text()) if p.exists() else {}

def save_comm(layer, book, data):
    p = ROOT / 'data' / 'commentary' / layer / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        existing.setdefault(ch, {})
        for v, entry in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = entry

ZECHARIAH = {
  "1": {
    "1": {"type": "theme", "note": "The prophetic commission to 'return to me and I will return to you' (v3) is prefaced here with YHWH's earlier anger against the ancestors — the divine patience that waited through judgment. Jesus embodies this returning-God in his ministry of repentance: 'Repent, for the kingdom of heaven is at hand' (Matt 4:17). The call to return that Zechariah re-issues finds its ultimate divine voice in the Son."},
    "2": {"type": "revelation of God", "note": "'YHWH was very angry with your fathers' — the divine wrath that the entire prophetic tradition proclaims is not left unresolved in the NT. Paul writes that 'Christ redeemed us from the curse of the law' (Gal 3:13) and that 'God was reconciling the world to himself in Christ, not counting men's sins against them' (2 Cor 5:19). The anger of v2 finds its absorbing resolution in the cross."},
    "3": {"type": "theme", "note": "'Return to me and I will return to you.' This mutual-return pattern drives Jesus's parable of the prodigal son (Luke 15:20 — 'while he was still a long way off, his father ran to him') and underlies the NT's theology of reconciliation. The Father who waits and runs to meet the returning son embodies what Zechariah announces."},
    "4": {"type": "theme", "note": "'Do not be like your fathers to whom the former prophets cried out.' The prophetic indictment of ancestral hardness becomes, in the NT, the pattern of the generation that rejects the Son (Matt 23:29-32 — 'your fathers killed the prophets and you build their tombs'). The failure warned against here is the failure that the passion narrative documents."},
    "5": {"type": "theme", "note": "'Your fathers — where are they? And the prophets — do they live forever?' The transience of human life and leadership is the backdrop against which Christ's eternal priesthood stands out: 'he holds his priesthood permanently, because he continues forever' (Heb 7:24). Zechariah's mortality-question is answered by the one who said 'I am the resurrection and the life' (John 11:25)."},
    "6": {"type": "theme", "note": "'Did not my words and my statutes overtake your fathers?' The living and active word of God that pursued the ancestors (Heb 4:12-13) is, in the NT, identified with the incarnate Word: 'In the beginning was the Word' (John 1:1). The word that will not return empty (Isa 55:11) has become flesh and dwelt among us."},
    "7": {"type": "shadow", "note": "The dated formula — 24th day, 11th month, 2nd year of Darius — introduces the eight night visions. Historical anchoring within prophecy signals real fulfillment in real time. The same eschatological framework (visionary revelation pointing to coming intervention) governs the Book of Revelation, where the risen Christ unveils the visions to John."},
    "8": {"type": "shadow", "note": "The rider on a red horse among myrtle trees — the first of eight night visions — introduces the divine horseman motif that Revelation develops in chs 6 and 19. The rider in the myrtle grove patrols a world at rest; the rider of Rev 19:11 ('Faithful and True') judges and makes war. The myrtle tree itself (lowly, fragrant) is a symbol of restored Israel (Isa 41:19; 55:13)."},
    "9": {"type": "shadow", "note": "The prophet's dialogue with the interpreting angel ('What are these?') is the standard form of apocalyptic interpretation — the prophet receives what he does not understand and is given the key. This pattern structures the revelation of Revelation, where John repeatedly receives interpreters (Rev 7:13-14; 17:7)."},
    "10": {"type": "shadow", "note": "'Those are the ones YHWH has sent to patrol the earth' — the divine horsemen as agents of sovereign knowledge and control. The risen Christ in Rev 1:13-16 walks among the lampstands with eyes like blazing fire — omniscient surveillance of his church. The patrols of the myrtle-grove vision are the OT framework for Christ's post-resurrection lordship over all the earth."},
    "11": {"type": "revelation of God", "note": "'The whole earth is at rest and quiet' — a moment of deceptive peace before YHWH's decisive intervention. The quiet earth is not a blessing; it is the silence before the storm of salvation. Rev 8:1 uses cosmic silence before the opening of judgment; here the silence sets the stage for the divine warrior to act. The patience of God (2 Pet 3:9) precedes the decisive hour."},
    "12": {"type": "direct", "note": "'O YHWH of hosts, how long will you have no mercy on Jerusalem and the cities of Judah, against which you have been angry these seventy years?' The anguished 'how long?' of the intercessory angel drives toward the cross as the moment when the question is finally answered. Christ absorbs the 'how long?' of divine patience in his passion (Luke 18:7-8 — 'will not God give justice to his elect who cry to him day and night?')."},
    "13": {"type": "revelation of God", "note": "'YHWH answered the angel who talked with me with comforting and gracious words.' The divine comfort that follows the intercession is the pattern of grace: God's response to the cry of his suffering people is consolation. Paul grounds Christian comfort in 'the God of all comfort who comforts us in all our affliction' (2 Cor 1:3-4) — the character revealed in this exchange."},
    "14": {"type": "revelation of God", "note": "'I am exceedingly jealous for Jerusalem and for Zion' — the divine <em>qin'ah</em> (jealousy/zeal) that drives YHWH to restore his city. Jesus enters Jerusalem with the same jealousy — the temple cleansing prompted John to recall 'zeal for your house will consume me' (John 2:17, quoting Ps 69:9). The Father's jealousy for his city finds incarnate expression in the Son."},
    "15": {"type": "revelation of God", "note": "'I am exceedingly angry with the nations that are at ease; for I was only a little angry with Israel, but they furthered the disaster.' Divine justice applies the same standard to all nations. The eschatological judgment of the nations (Matt 25:31-46; Rev 20:11-15) is the culmination of the divine anger first directed at the complacent powers."},
    "16": {"type": "direct", "note": "'Therefore, says YHWH, I have returned to Jerusalem with compassion; my house will be built in it.' YHWH's return to his house is fulfilled in Christ's coming: 'The Word became flesh and dwelt among us' (John 1:14) and Jesus's dramatic arrival at the temple ('My house will be called a house of prayer' Matt 21:13). The return of YHWH to his temple that Zechariah announces is the incarnation."},
    "17": {"type": "type", "note": "'My cities will again overflow with prosperity and YHWH will again comfort Zion' — the type of eschatological abundance fulfilled in the NT's vision of the new Jerusalem (Rev 21:1-4) and the kingdom feast (Luke 14:15-24; Rev 19:9). The overflowing cities of the restoration are the OT type of the overflowing community of resurrection life."},
    "18": {"type": "shadow", "note": "The four horns that scattered Judah, Israel, and Jerusalem — the worldly powers that oppose and disperse God's people — correspond to the beast empires of Daniel (Dan 7-8) and the nations that gather against Jerusalem in Zech 14. Christ's resurrection is the definitive defeat of all such powers: 'All authority in heaven and earth has been given to me' (Matt 28:18)."},
    "19": {"type": "shadow", "note": "'These are the horns that scattered Judah so that no one raised his head.' The humiliation of the people under oppressive power is the condition from which Christ delivers. Mary's Magnificat (Luke 1:51-52) celebrates this reversal: 'He has scattered the proud... he has brought down the mighty from their thrones and exalted those of humble estate.'"},
    "20": {"type": "shadow", "note": "The four craftsmen/smiths sent to terrify and cast down the four horns represent divine agents of overthrow. The principle — that YHWH always raises up instruments to break the instruments of oppression — reaches its apex in the cross, where Christ 'disarmed the rulers and authorities and put them to open shame, by triumphing over them' (Col 2:15)."},
    "21": {"type": "shadow", "note": "'These have come to terrify them, to cast down the horns of the nations who lifted up their horns against the land of Judah to scatter it.' The complete overthrow of all opposing powers is the eschatological horizon — the 'last enemy destroyed' (1 Cor 15:26). The craftsmen who cast down the horns are the OT shadow of Christ's work in his death and parousia."}
  },
  "2": {
    "1": {"type": "shadow", "note": "The man with a measuring line — going to measure Jerusalem — introduces the vision of the city that cannot be contained. Rev 21:15-17 parallels this closely: an angel with a measuring rod measures the new Jerusalem. The city's measurement reveals its fullness and security; what is measured belongs to God and is under his care."},
    "2": {"type": "shadow", "note": "'Where are you going?' / 'To measure Jerusalem, to see what is its width and length' — the measuring of the city anticipates the NT's language of the church as the measured, known, and protected dwelling of God (Rev 11:1-2; 21:15-17). The concern for dimensions reflects the divine ownership and care for the people who constitute the city."},
    "3": {"type": "shadow", "note": "The second angel's interception with more information — 'run, say to that young man...' — shows that the plan for Jerusalem exceeds what a measuring line can contain. The city of God will be greater than its measurer expects. This excess-of-expectation characterizes the NT's vision of the church: 'far more abundantly than all that we ask or think' (Eph 3:20)."},
    "4": {"type": "direct", "note": "'Jerusalem will be inhabited as villages without walls, because of the multitude of people and livestock in it.' The unwalled city — security without fortification — is fulfilled in the open, borderless community of the gospel. Acts 1:8 sends the gospel to the ends of the earth; Eph 2:14 declares 'he broke down the dividing wall of hostility.' The city without walls is the Pentecost church growing beyond all confinement."},
    "5": {"type": "revelation of God", "note": "'I will be to her a wall of fire all around, says YHWH, and I will be the glory in her midst.' Christ is declared 'our refuge and strength' (Ps 46:1) and 'the glory of God' dwelling in the church (John 17:22; Rev 21:23). The protective presence that Zechariah envisions as fire is the Spirit poured out at Pentecost (Acts 2:3 — 'divided tongues as of fire')."},
    "6": {"type": "theme", "note": "'Up! Up! Flee from the land of the north.' The call to exodus from Babylon — the city of this world — is the NT's call to eschatological separation: 'Come out from her, my people' (Rev 18:4); 'For here we have no lasting city, but we seek the city that is to come' (Heb 13:14). The call to flee is a call to follow Christ out of the present world-order."},
    "7": {"type": "theme", "note": "'Escape to Zion, you who dwell with the daughter of Babylon.' The urgent appeal to leave Babylon for Zion maps onto the NT contrast between the city of destruction and the city of God (Heb 12:22; Rev 21:2). Christ's invitation — 'Come to me, all who labor and are heavy laden' (Matt 11:28) — is the personal form of this communal call."},
    "8": {"type": "revelation of God", "note": "'Whoever touches you touches the apple of his eye.' The divine tenderness toward Israel — the pupil-of-the-eye image from Deut 32:10 — reveals a God who takes any assault on his people personally. Jesus expresses this identification with his people: 'Truly, I say to you, as you did it to one of the least of these my brothers, you did it to me' (Matt 25:40); 'Saul, Saul, why are you persecuting me?' (Acts 9:4)."},
    "9": {"type": "revelation of God", "note": "'I will wave my hand over them... and you will know that YHWH of hosts has sent me.' The divine warrior striking the nations on behalf of his people is the pattern of both the exodus and the eschaton. The one who is sent yet is YHWH — the Angel of YHWH — points toward the Trinitarian pattern of the Father sending the Son (John 3:17; Gal 4:4)."},
    "10": {"type": "direct", "note": "'Sing for joy and be glad, O daughter of Zion, for behold I am coming and I will dwell in your midst.' Zeph 3:14-17 uses the same 'daughter of Zion rejoice' formula for YHWH-the-King's arrival. John 12:15 quotes Zech 9:9's version of this arrival for Jesus's triumphal entry. The joyful arrival of YHWH in Zion is fulfilled in the incarnation — the Word tabernacling among his people (John 1:14)."},
    "11": {"type": "direct", "note": "'Many nations will join themselves to YHWH in that day and will be my people.' The Gentile inclusion in the covenant community is the central NT theme: 'he has made us both one and has broken down the dividing wall of hostility' (Eph 2:14); 'there is neither Jew nor Greek' (Gal 3:28). Christ is the one through whom the nations are joined to YHWH — 'that he might create in himself one new man' (Eph 2:15)."},
    "12": {"type": "type", "note": "'YHWH will inherit Judah as his portion in the holy land and will again choose Jerusalem.' The divine inheritance of the land is the OT type fulfilled in Christ's inheritance of all things: 'he is heir of all things' (Heb 1:2); 'Ask of me, and I will make the nations your heritage' (Ps 2:8). The father's inheritance of the land points to the Son's inheritance of the cosmos."},
    "13": {"type": "theme", "note": "'Be silent, all flesh, before YHWH, for he has roused himself from his holy dwelling.' The call to cosmic silence before the divine action is a recurring eschatological motif: Hab 2:20; Rev 8:1 (silence in heaven for half an hour before judgment). The silence before YHWH's action is the silence of awe before the cross — the moment when God himself acts decisively."}
  },
  "3": {
    "1": {"type": "direct", "note": "The courtroom scene — Joshua the high priest standing before the angel of YHWH while Satan stands at his right hand to accuse him — is one of the most direct anticipations of the NT's atonement theology. Satan as accuser (Rev 12:10 — 'the accuser of our brothers who accuses them before our God day and night') is here silenced by YHWH's own intervention. Christ is 'one who intercedes for us' (Rom 8:34) and 'our advocate with the Father' (1 John 2:1)."},
    "2": {"type": "direct", "note": "'YHWH rebuke you, Satan! YHWH who has chosen Jerusalem rebuke you! Is not this a brand plucked from the fire?' The divine rebuke of Satan prefigures Jesus's rebukes of demonic powers (Matt 4:10; 16:23; Mark 1:25; Luke 4:35). 'Brand plucked from the fire' — the miraculous rescue of the guilty — is the logic of grace: salvation not of those who deserved it but of those consumed by the fire of judgment. Jude 9 echoes this exact dispute over rescue."},
    "3": {"type": "direct", "note": "'Joshua was standing before the angel, clothed in filthy garments.' Filthy garments represent moral defilement in the divine court — Isa 64:6 ('all our righteous deeds are like polluted garments'). The high priest who should be pure before God is himself polluted. This is the human condition Paul describes: 'no one is righteous, not even one' (Rom 3:10). The scene sets up the great exchange of vv4-5."},
    "4": {"type": "direct", "note": "'Remove the filthy garments from him... See, I have taken your iniquity away from you and I will clothe you with pure vestments.' The exchange of filthy for clean garments is the core metaphor for justification: God removes the sinner's guilt and clothes him with righteousness. Isa 61:10: 'he has clothed me with garments of salvation'; Rev 7:13-14: the great multitude in white robes 'have washed their robes and made them white in the blood of the Lamb.' Christ's righteousness imputed is this scene enacted."},
    "5": {"type": "direct", "note": "'Let them put a clean turban on his head.' The high priest's turban bore the gold plate inscribed 'Holy to YHWH' (Exod 28:36-37). Restoring the turban restores the high priest's office and sanctification — he can stand before God and represent the people. Christ's own sanctification and priestly consecration (Heb 5:5-6; John 17:19 — 'for their sake I consecrate myself') is the fulfillment of Joshua's re-clothing."},
    "6": {"type": "theme", "note": "The angel of YHWH solemnly charges Joshua — the conditional promise is given. The charge functions as a statement of the priestly vocation: walk in YHWH's ways, keep his charge, judge his house. Jesus fulfills these priestly conditions perfectly and grants their benefits to those who are in him: 'For by a single offering he has perfected for all time those who are being sanctified' (Heb 10:14)."},
    "7": {"type": "theme", "note": "'If you walk in my ways... then you shall rule my house and have charge of my courts, and I will give you the right of access among those who are standing here.' The conditional promise of access to God — through faithful obedience — is fulfilled unconditionally in Christ for those who are in him. Heb 4:16: 'Let us then with confidence draw near to the throne of grace.' The 'right of access' is the NT's confident <em>prosagoge</em> (Eph 2:18; Rom 5:2)."},
    "8": {"type": "direct", "note": "'Behold I am going to bring my servant the Branch.' <em>tsemach</em> (Branch/Sprout) is a messianic title: Isa 4:2 (Branch of YHWH), Isa 11:1 (shoot from the stump of Jesse), Jer 23:5 and 33:15 (righteous Branch for David), Zech 6:12 (the man whose name is Branch). Luke 1:78 uses the Greek equivalent <em>anatole</em> (rising/Branch) for the coming of Christ: 'the sunrise shall visit us from on high.' The Branch announced here is Jesus."},
    "9": {"type": "direct", "note": "'Behold, the stone that I have set before Joshua — on this one stone are seven eyes. I will engrave its inscription and I will remove the iniquity of this land in a single day.' The stone with seven eyes = the Lamb with seven eyes (Rev 5:6 — 'seven eyes, which are the seven spirits of God sent out into all the earth'). The removal of iniquity 'in a single day' is fulfilled at the cross — the once-for-all sacrifice: 'he has appeared once for all at the end of the ages to put away sin by the sacrifice of himself' (Heb 9:26)."},
    "10": {"type": "type", "note": "'In that day you will invite each other to come under your vine and under your fig tree.' The eschatological peace of neighbor-hospitality under vine and fig tree echoes Mic 4:4 (the messianic kingdom) and appears in John 1:48 where Jesus sees Nathanael 'under the fig tree' — the moment of messianic recognition. The vine and fig tree as symbols of kingdom shalom find their personal embodiment in the one who is himself 'the true vine' (John 15:1)."}
  },
  "4": {
    "1": {"type": "shadow", "note": "The angel wakes the prophet as if from sleep — the visionary state as a mode of divine communication that transcends normal consciousness. The Spirit's waking is the pattern of prophetic revelation; the NT identifies this revelatory agency with the Spirit of Christ (1 Pet 1:11; 2 Pet 1:21)."},
    "2": {"type": "type", "note": "The golden lampstand (<em>menorah</em>) with seven lamps and seven pipes is the central symbol of the divine presence and light. Jesus identifies himself as 'the light of the world' (John 8:12) and the risen Christ walks among seven golden lampstands (Rev 1:12-13; 2:1) — the churches. The menorah's light is the OT type; Christ and his Spirit-indwelt church are the fulfillment."},
    "3": {"type": "type", "note": "The two olive trees flanking the lampstand supply oil to the lamps without ceasing. In Rev 11:4, 'these are the two olive trees and the two lampstands that stand before the Lord of the earth' — the two witnesses who prophesy in Christ's name. The continuous supply of oil = the unceasing provision of the Spirit (Acts 2; John 7:37-39). Christ as the anointed one (<em>mashiach</em>) is the ultimate source of the oil."},
    "4": {"type": "shadow", "note": "'What are these, my lord?' The prophet's question invites the interpretive key. Apocalyptic dialogue — the seer asking and the angel explaining — structures both Daniel and Revelation; the pattern models how the community receives divine revelation: through asking, seeking, knocking (Matt 7:7-8)."},
    "5": {"type": "shadow", "note": "'Do you not know what these are?' The angel's counter-question emphasizes that these symbols have meaning, and that meaning will be given. The pedagogy of the parables follows a similar logic: the disciples ask the meaning and Jesus explains (Matt 13:10-17). The riddle-and-explanation pattern is a mode of divine instruction that creates expectant receptivity."},
    "6": {"type": "direct", "note": "'Not by might, nor by power, but by my Spirit, says YHWH of hosts.' The supremacy of the Spirit over human force defines the new-covenant mode of God's action. Jesus is anointed by the Spirit for his mission (Luke 4:18; Isa 61:1 — 'the Spirit of the Lord is upon me'). The early church moves not by political force but by the Spirit's power (Acts 1:8). This verse is the hermeneutical key to how the kingdom comes in Christ."},
    "7": {"type": "direct", "note": "'Who are you, O great mountain? Before Zerubbabel you shall become a plain; and he shall bring forward the top stone amid shouts of Grace, grace to it!' The obstacle-mountain leveled by divine power is the pattern of the impossible made possible. Jesus: 'If you have faith like a grain of mustard seed, you will say to this mountain, Move...' (Matt 21:21). The 'top stone' (<em>rosh ha-'even</em>) celebrated with cries of grace is the capstone/cornerstone — Eph 2:20 identifies Christ as 'the cornerstone.' The shouts of grace are the NT's response to the one by whose grace it is all done."},
    "8": {"type": "shadow", "note": "The word of YHWH came again to the prophet — the revelatory double is a literary device for emphasis and structural balance in the vision sequence. The patterning of divine speech in twos and threes throughout the prophets mirrors the Trinitarian fullness of revelation."},
    "9": {"type": "type", "note": "'The hands of Zerubbabel have laid the foundation of this house; his hands shall also complete it.' Zerubbabel as the one who both begins and completes the temple is a type of Christ: 'Jesus, the founder and perfecter of our faith' (Heb 12:2); 'he who began a good work in you will bring it to completion at the day of Jesus Christ' (Phil 1:6). The builder who finishes what he starts is the assurance of salvation's completion."},
    "10": {"type": "type", "note": "'Who has despised the day of small things? These seven rejoice to see the plumb line in the hand of Zerubbabel; these are the eyes of YHWH which range through the whole earth.' The seven eyes of YHWH (= the seven eyes of the Lamb in Rev 5:6) oversee the construction with omniscient care. The 'day of small things' — the humble beginning that looks unpromising — is the pattern of the kingdom: 'the mustard seed, the smallest of all seeds' (Matt 13:32), the stable in Bethlehem."},
    "11": {"type": "type", "note": "'What are these two olive trees on the right and the left of the lampstand?' The two olive trees as the source of the lamp's oil point to the two primary channels through which the Spirit's anointing flows. The NT names these as the offices of prophet and king (both anointed by oil in Israel), which are unified in Christ as the prophet-priest-king."},
    "12": {"type": "type", "note": "'What are the two branches of the olive trees... that pour out the golden oil through the two golden pipes?' The image of oil flowing through pipes to the lamp is the OT picture of spiritual supply without human intermediary — grace flowing directly from its source. John 15:5 uses the vine-and-branches image for the same direct supply: 'I am the vine; you are the branches.'"},
    "13": {"type": "shadow", "note": "'Do you not know what these are?' The interpretive question demands the humility of not-knowing — the posture of the learner before the Teacher. Jesus's teaching ministry is characterized by questions that expose the disciples' need for illumination (Mark 4:13; 8:17-21)."},
    "14": {"type": "direct", "note": "'These are the two sons of oil who stand before the Lord of the whole earth' — the two anointed figures (Joshua the priest and Zerubbabel the king) who stand in YHWH's presence. The priest-king duality is unified in Christ: the messianic Psalm 110:4 ('you are a priest forever after the order of Melchizedek') applies to David's lord who is also seated at God's right hand. Heb 7:1-3 identifies Melchizedek as the type of Christ's eternal priesthood and kingship."}
  },
  "5": {
    "1": {"type": "shadow", "note": "The flying scroll (20 x 10 cubits = same dimensions as the porch of Solomon's Temple, 1 Kgs 6:3) is the curse of the law going out across the land. The law's curse permeating the land is what Paul describes in Gal 3:10: 'all who rely on works of the law are under a curse.' The flying scroll's dimensions connecting it to the temple signal that judgment originates from the place of divine presence — the law is holy but condemning (Rom 7:12)."},
    "2": {"type": "shadow", "note": "The scroll's dimensions — 20 cubits long, 10 cubits wide — are the dimensions of the temple porch (1 Kgs 6:3) and of the holy place's length and width. The scroll that fills the land with curse is temple-sized: the law given at the sanctuary is the measure by which the land is judged. Christ 'redeemed us from the curse of the law by becoming a curse for us' (Gal 3:13) — taking the temple-scroll's condemnation on himself."},
    "3": {"type": "theme", "note": "'This is the curse that goes out over the face of the whole land.' The universal scope of the curse echoes Rom 3:23: 'all have sinned and fall short of the glory of God.' The scroll's two sides — theft and false swearing — represent the two tables of the law (obligations to neighbor, obligations to God). Christ bears 'the punishment that brought us peace' (Isa 53:5), fulfilling the curse's demand."},
    "4": {"type": "theme", "note": "'I will send it out, says YHWH of hosts, and it shall enter the house of the thief and the house of one who swears falsely.' The penetrating judgment that enters every house is Heb 4:12-13: 'the word of God is living and active, sharper than a two-edged sword... discerning the thoughts and intentions of the heart.' No hidden sin escapes; the cross is where exposed sin meets absorbing grace."},
    "5": {"type": "shadow", "note": "The second vision: the ephah (large grain-measure basket) going out — a container of commercial life now containing the concentrated 'iniquity' of the land. The visualization of sin as a contained thing points toward the atonement's logic: sin must be removed, not merely overlooked. The scapegoat ritual (Lev 16:20-22) embodies the same logic — sin loaded onto a carrier and sent away."},
    "6": {"type": "shadow", "note": "'This is their iniquity throughout the land.' Iniquity personified and contained in a measuring basket — a striking externalization of what is ordinarily internal. The Day of Atonement theology requires exactly this: sin must be taken up and carried away. The NT declares: 'he himself bore our sins in his body on the tree' (1 Pet 2:24)."},
    "7": {"type": "shadow", "note": "The lead cover (<em>kikar 'oferet</em>) sealing the ephah contains the 'wickedness.' Lead is heavy — used to seal; the sin cannot escape its container. The sealing of sin for removal anticipates the atonement's finality: 'he has appeared once for all at the end of the ages to put away sin by the sacrifice of himself' (Heb 9:26). Once carried and sealed, the sin is dealt with definitively."},
    "8": {"type": "shadow", "note": "'This is Wickedness' — the woman thrust back into the basket and the lead weight pushed down over her. Wickedness as a personified force that must be contained and exiled echoes Rev 17-18's 'Babylon the Great' who is finally judged and removed. The feminine personification may allude to the 'queen of heaven' cult that Israel pursued; her containment signals the end of idolatry."},
    "9": {"type": "shadow", "note": "Two women with wings like a stork carry the ephah away. The stork (<em>chasidah</em>, 'the loyal/kind one') is ritually unclean (Lev 11:19) — an ironic choice of removal-agent, unclean creatures carrying away the iniquity. The agents of sin's removal are themselves outside the clean order, pointing to the NT dynamic where Christ 'who knew no sin was made to be sin for us' (2 Cor 5:21)."},
    "10": {"type": "shadow", "note": "'Where are they taking the ephah?' / 'To the land of Shinar, to build a house for it.' Shinar = Babylon (Gen 11:2) — the place of human pride and exile. Sin is returned to its city of origin, to be housed there permanently. This exile of iniquity from the land of God's presence is the OT picture of what the cross accomplishes: sin defeated and contained at the place of judgment, unable to return."},
    "11": {"type": "shadow", "note": "'When it is prepared, they will set the basket down there on its base.' The iniquity installed in its Babylonian home — removed from the holy land and enshrined far away — is the OT type of Christ's removal of sin from his people. The final Babylon of Revelation (chs 17-18) is destroyed precisely because it is the city that houses the world's accumulated wickedness; its destruction is the ultimate removal of the ephah."}
  },
  "6": {
    "1": {"type": "shadow", "note": "The four chariots emerging from between two bronze mountains — the final of the eight night visions — represent the four winds/spirits of heaven going throughout the earth under divine command. The bronze mountains (like the temple pillars Jachin and Boaz, 1 Kgs 7:15-21) frame the exit of divine providential agents. Rev 6:1-8's four horsemen draw on this vision; the rider who overcomes on the white horse (Rev 19:11) is the ultimate divine warrior emerging from the Father's presence."},
    "2": {"type": "shadow", "note": "The first chariot with red horses corresponds to the red horse of Rev 6:4 (taking peace from the earth). The chariot-horse symbolism — borrowed from the divine cavalry patrols of ch1 — now escalates to full mobilization. The divine warrior who surveys in ch1 now acts in ch6; the escalation from patrol to campaign is the movement from patience to judgment."},
    "3": {"type": "shadow", "note": "Black, white, and dappled horses complete the four teams. The colors correspond to different modes of divine action: red = war/blood, black = famine/death, white = victory/conquest, dappled = death/plague (Rev 6:8). The comprehensive array covers all the instruments of divine providence — conquest, war, famine, death. Christ who 'upholds all things by the word of his power' (Heb 1:3) is the one to whom all these agencies are ultimately subject."},
    "4": {"type": "shadow", "note": "'What are these, my lord?' The prophet's query continues the interpretive dialogue of apocalyptic revelation. The question marks the boundary of human understanding and the necessity of divine disclosure — the same dynamic as the disciples' questions about parables (Matt 13:36) and Nicodemus's night question (John 3:9)."},
    "5": {"type": "shadow", "note": "'These are the four winds of heaven going out after presenting themselves before the Lord of all the earth.' The four winds standing before YHWH and then going forth embody absolute divine sovereignty: nothing occurs in history without first passing before the Lord. Dan 7:2 uses 'the four winds of heaven' for the same total historical scope. Christ is declared 'heir of all things' and 'Lord of all the earth' (Heb 1:2; Acts 10:36)."},
    "6": {"type": "shadow", "note": "The north chariot (the direction of judgment in Hebrew prophecy, Jer 1:14) and the south chariot represent comprehensive directional coverage. No quarter of the earth is exempt from divine providential action. The missionary commission of Matt 28:19-20 ('make disciples of all nations') mirrors this comprehensive geographic scope of divine action."},
    "7": {"type": "shadow", "note": "'The strong ones were eager to go to patrol the earth.' The horses of divine providence pressing eagerly into their mission echoes Hab 3:8 (YHWH riding to save his people). The risen Christ's commission — 'Go therefore' (Matt 28:19) — sends his emissaries with the same urgency, empowered by the one who has 'all authority in heaven and on earth.'"},
    "8": {"type": "revelation of God", "note": "'Those going toward the north country have set my Spirit at rest.' The chariots going north (the direction of Israel's historic enemies — Babylon, Assyria) have accomplished YHWH's will there, and his Spirit is satisfied/at rest. The idea of YHWH's Spirit being moved toward or finding rest in history's events is the OT basis for Paul's 'all things work together for good' (Rom 8:28) — the Spirit superintending outcomes toward the purposes of God."},
    "9": {"type": "shadow", "note": "The word of YHWH came to Zechariah — the introductory formula for the crowning episode, transitioning from visionary to symbolic action. The shift from night vision to daylight enacted prophecy signals that what follows is not merely a vision but a performed declaration intended to be understood and remembered."},
    "10": {"type": "shadow", "note": "Three exiles named — Heldai, Tobijah, Jedaiah — have come from Babylon bearing silver and gold for the temple. The provision for the crown comes from the diaspora returning — the resources of exile repurposed for the sanctuary. The Gentile provision for the building of God's house anticipates the NT dynamic: the nations' wealth flowing into the kingdom (Isa 60:5-7; Rev 21:24-26)."},
    "11": {"type": "direct", "note": "'Take the silver and gold, make crowns, and set them on the head of Joshua son of Jehozadak, the high priest.' A crown placed on the high priest's head — the royal crown on the priestly figure — enacts the fusion of offices that Ps 110 promises: YHWH's declaration to the Davidic king, 'you are a priest forever after the order of Melchizedek.' The crowning of Joshua is a symbolic act pointing to the one who will hold both offices permanently. Christ's session at the Father's right hand as both King and High Priest (Heb 4:14; 8:1) fulfills this coronation."},
    "12": {"type": "direct", "note": "'Thus says YHWH of hosts, Here is the man whose name is the Branch: for he shall branch out from his place and he shall build the temple of YHWH.' <em>tsemach</em> (Branch) as the explicit name of the coming Davidic figure; Luke 1:78 uses the Greek equivalent <em>anatole</em> (rising/dawn/Branch) for Christ's coming. 'He shall build the temple of YHWH' is fulfilled in Jesus's promise: 'I will build my church' (Matt 16:18) and the church as the living temple (Eph 2:20-22; 1 Pet 2:4-5)."},
    "13": {"type": "direct", "note": "'It is he who shall build the temple of YHWH and shall bear royal honor and shall sit and rule on his throne. And he shall be a priest on his throne, and the counsel of peace shall be between them both.' The priest-king seated on his throne is the most explicit OT statement of the Melchizedekan order: a single figure who is simultaneously royal and priestly. Christ's ascension and session (Heb 8:1 — 'we have such a high priest, one who is seated at the right hand of the throne of the Majesty in heaven') is this verse's fulfillment. The 'counsel of peace' between the two offices is the <em>shalom</em> that the priest-king mediates."},
    "14": {"type": "type", "note": "The crown remains in the temple as a memorial — a standing sign of the royal-priestly hope. The physical crown as a permanent reminder of the promised figure is the OT type of the NT's ongoing proclamation: 'we proclaim Christ crucified' (1 Cor 1:23) and 'as often as you eat this bread and drink the cup, you proclaim the Lord's death until he comes' (1 Cor 11:26). The memorial of the hope becomes the memorial of the fulfillment."},
    "15": {"type": "direct", "note": "'And those who are far off shall come and help to build the temple of YHWH.' The distant ones participating in the building of the temple is fulfilled in the NT church's Gentile mission. Eph 2:13: 'But now in Christ Jesus you who once were far off have been brought near by the blood of Christ.' The inclusion of the distant ones in the building project is Paul's central ecclesiological theme — the Gentiles co-builders of the spiritual temple."}
  },
  "7": {
    "1": {"type": "shadow", "note": "The fourth year of Darius — the dated oracle that interrupts the eight visions. The dating formula grounds the prophetic word in historical reality; eschatological hope is not detached from present circumstances. The same tension — present need and future promise — characterizes Jesus's teaching: 'in the world you will have tribulation. But take heart; I have overcome the world' (John 16:33)."},
    "2": {"type": "theme", "note": "Bethel sent men to entreat the favor of YHWH and inquire about fasting — religious observance as a sincere question. The sincerity of the inquiry does not automatically yield the right answer; YHWH's response redirects from ritual to ethics. Jesus makes the same move: 'I desire mercy, not sacrifice' (Matt 9:13, quoting Hos 6:6), redirecting religious performance toward the heart."},
    "3": {"type": "theme", "note": "'Should I mourn and fast in the fifth month, as I have done for so many years?' The religious question about fasting echoes the disciples' question to Jesus: 'Why do we and the Pharisees fast, but your disciples do not fast?' (Matt 9:14). Jesus's answer — 'Can the wedding guests mourn as long as the bridegroom is with them?' — reframes fasting around his own presence, just as Zechariah's answer reframes fasting around ethical substance."},
    "4": {"type": "shadow", "note": "The word of YHWH of hosts came to Zechariah — the standard formula marking a new oracle. The divine response to the human question models prayer and response: the people ask, God answers, though the answer is deeper than the question anticipated. Jesus's teaching on prayer (Matt 7:7-11) promises divine responsiveness that exceeds the petitioner's request."},
    "5": {"type": "theme", "note": "'Was it for me that you fasted? When you eat and drink, do you not eat and drink for yourselves?' The prophetic critique of self-serving religion is central to Jesus's teaching in the Sermon on the Mount: fasting, prayer, and almsgiving done 'to be seen by others' are done 'for yourselves' (Matt 6:1-18). The God who sees in secret is the alternative to the audience that confirms self-serving piety."},
    "6": {"type": "theme", "note": "'When you eat and drink, is it not for yourselves?' The question exposes the self-referential core of religious activity divorced from justice and mercy. Paul reformulates this as the Eucharistic warning: 'anyone who eats and drinks without discerning the body eats and drinks judgment on himself' (1 Cor 11:29) — eating and drinking 'for yourself' at the Lord's table rather than for the body."},
    "7": {"type": "theme", "note": "'Were these not the words that YHWH proclaimed by the former prophets?' The continuity of the prophetic message across generations — justice, mercy, compassion — is the same continuity Jesus claims: 'Do not think I have come to abolish the Law or the Prophets; I have not come to abolish them but to fulfill them' (Matt 5:17). The ethical core of the prophets' message is not superseded but fulfilled in Christ."},
    "8": {"type": "shadow", "note": "The word of YHWH came to Zechariah, saying — the formula introducing the social ethics of vv9-10. The link between divine revelation and ethical demand is the same logic as James 1:27: 'religion that is pure and undefiled before God is this: to visit orphans and widows in their affliction.' God's word arriving always generates both belief and obedience."},
    "9": {"type": "theme", "note": "'Render true judgments, show kindness and mercy to one another.' The positive ethical commands — <em>mishpat 'emet</em> (true judgment), <em>chesed</em> (covenant loyalty/kindness), <em>rachamim</em> (compassion) — are the social expression of the divine character. Jesus's beatitudes (Matt 5:3-12) and the double love command (Matt 22:37-40) gather these prophetic demands into their christological fulfillment: Christ embodies each of these virtues and calls his followers to imitate him."},
    "10": {"type": "theme", "note": "'Do not oppress the widow, the fatherless, the sojourner, or the poor.' The prophetic quartet of the vulnerable — widow, orphan, stranger, poor — is the standard of covenant justice throughout the OT (Exod 22:21-22; Deut 24:17-21; Isa 1:17). Jesus announces his mission from Isa 61:1: 'he has anointed me to proclaim good news to the poor.' James 1:27 crystallizes the NT application. The protection of the vulnerable is a Christological demand because Christ himself was poor, homeless, and vulnerable."},
    "11": {"type": "theme", "note": "'But they refused to pay attention and turned a stubborn shoulder and stopped their ears.' Stubbornness against the prophetic word is the same pattern Jesus encounters and mourns: 'O Jerusalem, Jerusalem, you who kill the prophets and stone those who are sent to you! How often would I have gathered your children... but you were not willing' (Matt 23:37). The stubbornness of the ancestors is the warning that becomes reality in the generation that rejects the Son."},
    "12": {"type": "theme", "note": "'They made their hearts diamond-hard lest they should hear the law and the words that YHWH of hosts had sent by his Spirit through the former prophets.' The hard heart — the stony heart of Ezek 36:26 — is what Christ addresses in the new covenant: 'I will remove the heart of stone from your flesh and give you a heart of flesh' (Ezek 36:26). 'Spirit through the former prophets' is 1 Pet 1:11's testimony: 'the Spirit of Christ in them was indicating the sufferings of Christ and the subsequent glories.'"},
    "13": {"type": "theme", "note": "'As I called, and they did not hear, so they called, and I did not hear.' The prophetic principle of call-and-response — divine call unanswered producing divine silence — is the serious warning Christ applies to the parable of the tenants (Matt 21:33-43) and the wedding feast (Matt 22:1-14). Those who ignore the call eventually find themselves outside; but the same God who warns is the one who seeks the lost (Luke 15:3-7)."},
    "14": {"type": "theme", "note": "'I scattered them with a whirlwind among all the nations they had not known.' The final judgment — scattering among unknown nations — is the covenant-curse realized (Deut 28:64-68). Yet this same scattering becomes, in the NT, the instrument of mission: 'those who were scattered went about preaching the word' (Acts 8:4). What was judgment becomes gospel-advance under the sovereignty of Christ who 'turns mourning into dancing' (Ps 30:11)."}
  }
}

def main():
    existing = load_comm('mkt-christ', 'zechariah')
    merge_comm(existing, ZECHARIAH)
    save_comm('mkt-christ', 'zechariah', existing)
    print('Zechariah 1-7 christ written.')

if __name__ == '__main__':
    main()
